6	#include <tvm/support/cuda/nvtx.h>
7	
8	#include "../sampler/sampler.h"
9	#include "batch_prefill_base.h"
10	
11	namespace mlc {
12	namespace llm {
13	namespace serve {
14	
15	using tvm::support::NVTXScopedRange;
16	
17	/*!
18	 * \brief The action that prefills requests in the `waiting_queue` of
19	 * the engine state.
20	 * Aside from that, this action sends the computed KV data to remote
21	 * instances after computing the KV data.
22	 */
23	class DisaggRemoteSendActionObj : public BatchPrefillBaseActionObj {
24	 public:
25	  explicit DisaggRemoteSendActionObj(Array<Model> models,
26	                                     std::vector<ModelWorkspace> model_workspaces,
27	                                     EngineConfig engine_config,
28	                                     std::vector<tvm::ffi::json::Object> model_configs,
29	                                     Optional<EventTraceRecorder> trace_recorder,
30	                                     FRequestStreamCallback request_stream_callback, Device device)
31	      : BatchPrefillBaseActionObj(std::move(models), std::move(engine_config),
32	                                  std::move(model_configs), std::move(trace_recorder)),
33	        model_workspaces_(std::move(model_workspaces)),
34	        request_stream_callback_(std::move(request_stream_callback)),
35	        device_(device) {
36	    if (device.device_type == DLDeviceType::kDLCUDA ||
37	        device.device_type == DLDeviceType::kDLROCM) {
38	      // The compute stream is the default stream.
39	      compute_stream_ = DeviceAPI::Get(device)->GetCurrentStream(device);
40	    }
41	  }
42	
43	  // Mimicked from NewRequestPrefillActionObj::Step
44	  Array<Request> Step(EngineState estate) final {
45	    // - Find the requests in `waiting_queue` that can prefill in this step.
46	    std::vector<PrefillInput> prefill_inputs;
47	    {
48	      NVTXScopedRange nvtx_scope("DisaggRemoteSend getting requests");
49	      prefill_inputs = GetRequestStateEntriesToPrefill(estate);
50	      if (prefill_inputs.empty()) {
51	        return {};
52	      }
53	    }
54	
55	    int num_rsentries = prefill_inputs.size();
56	    {
57	      NVTXScopedRange nvtx_scope("DisaggRemoteSend matching prefix");
58	      for (int i = 0; i < num_rsentries; ++i) {
59	        MatchPrefixCache(estate, &prefill_inputs[i]);
60	      }
61	    }
62	
63	    auto tstart = std::chrono::high_resolution_clock::now();
64	
65	    // - Update status of request states from pending to alive.
66	    Array<String> request_ids;
67	    std::vector<RequestState> rstates_of_entries;
68	    std::vector<RequestStateStatus> status_before_prefill;
69	    UpdateRequestToAlive(prefill_inputs, estate, &request_ids, &rstates_of_entries,
70	                         &status_before_prefill);
71	
72	    // - Get embedding and run prefill for each model.
73	    // NOTE: we don't keep the logits as we don't run sampling in this action by design.
74	    std::vector<int> prefill_lengths;
75	    prefill_lengths.resize(/*size=*/num_rsentries, /*value=*/-1);
76	    for (int model_id = 0; model_id < static_cast<int>(models_.size()); ++model_id) {
77	      std::vector<int64_t> request_internal_ids;
78	      request_internal_ids.reserve(num_rsentries);
79	      ObjectRef embeddings = model_workspaces_[model_id].embeddings;
80	      int cum_prefill_length = 0;
81	      bool single_input =
82	          num_rsentries == 1 && prefill_inputs[0].rsentry->mstates[model_id]->inputs.size() == 1;
83	      std::vector<int64_t> cached_token_data;
84	      for (int i = 0; i < num_rsentries; ++i) {
85	        const RequestStateEntry& rsentry = prefill_inputs[i].rsentry;
86	        RequestModelState mstate = rsentry->mstates[model_id];
87	        auto [input_data, input_length] =
88	            ChunkPrefillInputData(mstate, prefill_inputs[i].max_prefill_length);
89	        if (prefill_lengths[i] == -1) {
90	          prefill_lengths[i] = input_length;
91	        } else {
92	          TVM_FFI_ICHECK_EQ(prefill_lengths[i], input_length);
93	        }
94	        mstate->num_prefilled_tokens += input_length;
95	
96	        TVM_FFI_ICHECK(mstate->draft_output_tokens.empty());
97	        TVM_FFI_ICHECK(mstate->draft_token_slots.empty());
98	        if (status_before_prefill[i] == RequestStateStatus::kPending &&
99	            !estate->prefix_cache->HasSequence(mstate->internal_id)) {
100	          // Add the sequence to the model.
101	          // If the sequence is already in prefix cache, it has also been added/forked in the
102	          // KVCache.
103	          TVM_FFI_ICHECK_EQ(rsentry->parent_idx, -1);
104	          models_[model_id]->AddNewSequence(mstate->internal_id);
105	          // Enable sliding window for the sequence if it is not a parent.
106	          if (rsentry->child_indices.empty()) {
107	            models_[model_id]->EnableSlidingWindowForSeq(mstate->internal_id);
108	          }
109	          DisaggConfig disagg_config = mstate->request->generation_cfg->debug_config.disagg_config;
110	          TVM_FFI_ICHECK(disagg_config.dst_group_offset.has_value());
111	          models_[model_id]->DisaggMarkKVSend(
112	              mstate->internal_id, disagg_config.kv_window_begin.value_or(0),
113	              disagg_config.kv_append_metadata[model_id], disagg_config.dst_group_offset.value());
114	        }
115	        request_internal_ids.push_back(mstate->internal_id);
116	        RECORD_EVENT(trace_recorder_, rsentry->request->id, "start embedding");
117	        for (int j = 0; j < static_cast<int>(input_data.size()); ++j) {
118	          if (!model_id && !prefill_inputs[i].is_decode) {
119	            mstate->prefilled_inputs.push_back(input_data[j]);
120	          }
121	          if (const auto* token_data = input_data[j].as<TokenDataNode>()) {
122	            cached_token_data.insert(cached_token_data.end(), token_data->token_ids.begin(),
123	                                     token_data->token_ids.end());
124	          } else {
125	            if (!cached_token_data.empty()) {
126	              embeddings = TokenData(cached_token_data)
127	                               ->GetEmbedding(models_[model_id],
128	                                              /*dst=*/!single_input ? &embeddings : nullptr,
129	                                              /*offset=*/cum_prefill_length);
130	              cum_prefill_length += cached_token_data.size();
131	              cached_token_data.clear();
132	            }
133	            embeddings = input_data[j]->GetEmbedding(models_[model_id],
134	                                                     /*dst=*/!single_input ? &embeddings : nullptr,
135	                                                     /*offset=*/cum_prefill_length);
136	            cum_prefill_length += input_data[j]->GetLength();
137	          }
138	        }
139	        RECORD_EVENT(trace_recorder_, rsentry->request->id, "finish embedding");
140	      }
141	      if (!cached_token_data.empty()) {
142	        embeddings = TokenData(cached_token_data)
143	                         ->GetEmbedding(models_[model_id],
144	                                        /*dst=*/!single_input ? &embeddings : nullptr,
145	                                        /*offset=*/cum_prefill_length);
146	        cum_prefill_length += cached_token_data.size();
147	        cached_token_data.clear();
148	      }
149	
150	      RECORD_EVENT(trace_recorder_, request_ids, "start prefill");
151	      Tensor logits =
152	          models_[model_id]->BatchPrefill(embeddings, request_internal_ids, prefill_lengths);
153	      RECORD_EVENT(trace_recorder_, request_ids, "finish prefill");
154	      TVM_FFI_ICHECK_EQ(logits->ndim, 3);
155	      TVM_FFI_ICHECK_EQ(logits->shape[0], 1);
156	      TVM_FFI_ICHECK_EQ(logits->shape[1], num_rsentries);
157	    }
158	
159	    // - Commit the prefix cache changes from previous round of action.
160	    // Note: we commit prefix cache changes here to overlap this commit with the GPU execution.
161	    estate->prefix_cache->CommitSequenceExtention();
162	
163	    // - We run synchronize to make sure that the prefill is finished.
164	    // We need explicit synchronization because we don't do sampling in this action.
165	    DeviceAPI::Get(device_)->StreamSync(device_, compute_stream_);
166	
167	    auto tend = std::chrono::high_resolution_clock::now();
168	    estate->metrics.engine_prefill_time_sum += static_cast<double>((tend - tstart).count()) / 1e9;
169	
170	    std::vector<Request> processed_requests =
171	        RemoveProcessedRequests(prefill_inputs, estate, rstates_of_entries);
172	    estate->running_rsentries_changed = true;
173	    return processed_requests;
174	  }
175	
176	 private:
177	  // Mimicked from BatchPrefillBaseActionObj::GetRequestStateEntriesToPrefill
178	  std::vector<PrefillInput> GetRequestStateEntriesToPrefill(EngineState estate) {
179	    // Preempt request state entries when decode cannot apply.
180	    const std::vector<RequestStateEntry>* running_rsentries;
181	    {
182	      NVTXScopedRange nvtx_scope("BatchDecode getting requests");
183	      running_rsentries = &estate->GetRunningRequestStateEntries();
184	      if (!(running_rsentries->size() <= models_[0]->GetNumAvailablePages())) {
185	        // Even the decode cannot be performed.
186	        // As a result, directly return without doing prefill.
187	        return {};
188	      }
189	    }
190	
191	    // Explicitly filter the waiting queue to only keep the requests
192	    // with disaggregation request kind "kRemoteSend".
193	    std::vector<Request> waiting_queue;
194	    waiting_queue.reserve(estate->waiting_queue.size());
195	    for (Request request : estate->waiting_queue) {
196	      if (request->generation_cfg->debug_config.disagg_config.kind ==
197	          DisaggRequestKind::kRemoteSend) {
198	        waiting_queue.push_back(request);
199	      }
200	    }
201	    if (waiting_queue.empty()) {
202	      // No request to prefill.
203	      return {};
204	    }
205	
206	    std::vector<std::vector<PrefillInput>> prefill_inputs_for_all_models;
207	    prefill_inputs_for_all_models.reserve(models_.size());
208	
209	    int num_running_rsentries = static_cast<int>(running_rsentries->size());
210	    // We first collect the inputs that can be prefilled for each model.
211	    // Then we make a reduction to return the maximum common inputs.
212	    for (int i = 0; i < static_cast<int>(models_.size()); ++i) {
213	      std::vector<PrefillInput> prefill_inputs;
214	      // - Try to prefill pending requests.
215	      int total_input_length = 0;
216	      int total_required_pages = 0;
217	      int num_available_pages;
218	      int current_total_seq_len;
219	      {
220	        NVTXScopedRange nvtx_scope("KV cache GetNumAvailablePages");
221	        num_available_pages = models_[i]->GetNumAvailablePages();
222	      }
223	      {
224	        NVTXScopedRange nvtx_scope("KV cache GetCurrentTotalSequenceLength");
225	        current_total_seq_len = models_[i]->GetCurrentTotalSequenceLength();
226	      }
227	
228	      int num_prefill_rsentries = 0;
229	      for (const Request& request : waiting_queue) {
230	        NVTXScopedRange nvtx_scope("Process request " + request->id);
231	        RequestState rstate = estate->GetRequestState(request);
232	        TVM_FFI_ICHECK_EQ(rstate->entries.size(), 1) << "n > 1 is not supported.";
233	        const RequestStateEntry& rsentry = rstate->entries[0];
234	        TVM_FFI_ICHECK(!rsentry->mstates[i]->inputs.empty())
235	            << "The request entry must have pending inputs.";
236	
237	        int input_length = rsentry->mstates[i]->GetInputLength();
238	        int num_require_pages = (input_length + engine_config_->kv_cache_page_size - 1) /
239	                                engine_config_->kv_cache_page_size;
240	        bool sliding_window_enabled = sliding_window_sizes_[i] != -1;
241	        int num_required_pages_under_sliding_window = std::numeric_limits<int>::max();
242	        if (sliding_window_enabled) {
243	          // Sliding window for model i is enabled.
244	          int max_single_request_page_requirement =
245	              1 + (sliding_window_sizes_[i] + engine_config_->kv_cache_page_size - 1) /
246	                      engine_config_->kv_cache_page_size;
247	          int num_total_prefilled_tokens = rsentry->mstates[i]->num_prefilled_tokens;
248	          int parent_ptr = rsentry->parent_idx;
249	          while (parent_ptr != -1) {
250	            num_total_prefilled_tokens +=
251	                rstate->entries[parent_ptr]->mstates[i]->num_prefilled_tokens;
252	            parent_ptr = rstate->entries[parent_ptr]->parent_idx;
253	          }
254	
255	          int num_pages_in_use = (std::min(num_total_prefilled_tokens, sliding_window_sizes_[i]) +
256	                                  engine_config_->kv_cache_page_size - 1) /
257	                                 engine_config_->kv_cache_page_size;
258	          num_required_pages_under_sliding_window =
259	              max_single_request_page_requirement - num_pages_in_use;
260	          num_require_pages = std::min(num_require_pages, num_required_pages_under_sliding_window);
261	          TVM_FFI_ICHECK_GE(num_require_pages, 0);
262	        }
263	
264	        total_input_length += input_length;
265	        total_required_pages += num_require_pages;
266	        // - Attempt 1. Check if the entire request state entry can fit for prefill.
267	        bool can_prefill = false;
268	        {
269	          NVTXScopedRange nvtx_scope("Attempt 1");
270	          for (int num_child_to_activate = rsentry->child_indices.size();
271	               num_child_to_activate >= 0; --num_child_to_activate) {
272	            while (!HasPrefillSpace(total_required_pages, sliding_window_enabled,
273	                                    (num_running_rsentries + num_prefill_rsentries),
274	                                    num_available_pages, current_total_seq_len, total_input_length,
275	                                    engine_config_->max_total_sequence_length)) {
276	              if (!estate->prefix_cache->TryFreeMemory()) break;
277	              // Update number of available pages after memory free.
278	              num_available_pages = models_[i]->GetNumAvailablePages();
279	              current_total_seq_len = models_[i]->GetCurrentTotalSequenceLength();
280	            }
281	            if (CanPrefill(estate, num_prefill_rsentries + 1 + num_child_to_activate,
282	                           total_input_length, total_required_pages, num_available_pages,
283	                           current_total_seq_len, num_running_rsentries, kv_state_kind_,
284	                           sliding_window_enabled)) {
285	              prefill_inputs.push_back(
286	                  {rsentry, input_length, num_child_to_activate, /*is_decode=*/false});
287	              num_prefill_rsentries += 1 + num_child_to_activate;
288	              can_prefill = true;
289	              break;
290	            }
291	          }
292	        }
293	        if (can_prefill) {
294	          continue;
295	        }
296	        total_input_length -= input_length;
297	        total_required_pages -= num_require_pages;
298	
299	        // - Attempt 2. Check if the request state entry can partially fit by input chunking.
300	        TVM_FFI_ICHECK_LE(total_input_length, engine_config_->prefill_chunk_size);
301	        if (engine_config_->prefill_chunk_size - total_input_length >= input_length ||
302	            engine_config_->prefill_chunk_size == total_input_length) {
303	          // 1. If the input length can fit the remaining prefill chunk size,
304	          // it means the failure of attempt 1 is not because of the input
305	          // length being too long, and thus chunking does not help.
306	          // 2. If the total input length already reaches the prefill chunk size,
307	          // the current request state entry will not be able to be processed.
308	          // So we can safely return in either case.
309	          break;
310	        }
311	        input_length = engine_config_->prefill_chunk_size - total_input_length;
312	        num_require_pages = (input_length + engine_config_->kv_cache_page_size - 1) /
313	                            engine_config_->kv_cache_page_size;
314	        if (sliding_window_enabled) {
315	          // Sliding window for model i is enabled.
316	          num_require_pages = std::min(num_require_pages, num_required_pages_under_sliding_window);
317	          TVM_FFI_ICHECK_GE(num_require_pages, 0);
318	        }
319	
320	        {
321	          NVTXScopedRange nvtx_scope("Attempt 2");
322	          total_input_length += input_length;
323	          total_required_pages += num_require_pages;
324	          if (CanPrefill(estate, num_prefill_rsentries + 1, total_input_length,
325	                         total_required_pages, num_available_pages, current_total_seq_len,
326	                         num_running_rsentries, kv_state_kind_, sliding_window_enabled)) {
327	            prefill_inputs.push_back({rsentry, input_length, 0, /*is_decode=*/false});
328	          }
329	        }
330	
331	        // - Prefill stops here.
332	        break;
333	      }
334	      prefill_inputs_for_all_models.push_back(prefill_inputs);
335	    }
336	
337	    // Reduce over the prefill inputs of all models.
338	    TVM_FFI_ICHECK(!prefill_inputs_for_all_models.empty());
339	    int num_prefill_inputs = prefill_inputs_for_all_models[0].size();
340	    for (int i = 1; i < static_cast<int>(prefill_inputs_for_all_models.size()); ++i) {
341	      num_prefill_inputs =
342	          std::min(num_prefill_inputs, static_cast<int>(prefill_inputs_for_all_models[i].size()));
343	    }
344	
345	    if (num_prefill_inputs == 0) {
346	      return {};
347	    }
348	
349	    // Add the decode requests to the prefill inputs if prefill mode is hybrid.
350	    std::vector<PrefillInput> prefill_inputs(prefill_inputs_for_all_models[0].begin(),
351	                                             prefill_inputs_for_all_models[0].end());
352	    {
353	      NVTXScopedRange nvtx_scope("reduction");
354	      for (int i = 1; i < static_cast<int>(prefill_inputs_for_all_models.size()); ++i) {
355	        // Prefill input lengths except the last one are supposed to be the same for all models.
356	        for (int j = 0; j < num_prefill_inputs - 1; ++j) {
357	          TVM_FFI_ICHECK(
358	              prefill_inputs_for_all_models[i][j].rsentry.same_as(prefill_inputs[j].rsentry));
359	          TVM_FFI_ICHECK_EQ(prefill_inputs_for_all_models[i][j].max_prefill_length,
360	                            prefill_inputs[j].max_prefill_length);
361	          prefill_inputs[j].num_child_to_activate =
362	              std::min(prefill_inputs[j].num_child_to_activate,
363	                       prefill_inputs_for_all_models[i][j].num_child_to_activate);
364	        }
365	        // The input length of the last input is the minimum among all models.
366	        TVM_FFI_ICHECK(prefill_inputs_for_all_models[i][num_prefill_inputs - 1].rsentry.same_as(
367	            prefill_inputs[num_prefill_inputs - 1].rsentry));
368	        prefill_inputs[num_prefill_inputs - 1].max_prefill_length =
369	            std::min(prefill_inputs[num_prefill_inputs - 1].max_prefill_length,
370	                     prefill_inputs_for_all_models[i][num_prefill_inputs - 1].max_prefill_length);
371	        prefill_inputs[num_prefill_inputs - 1].num_child_to_activate = std::min(
372	            prefill_inputs[num_prefill_inputs - 1].num_child_to_activate,
373	            prefill_inputs_for_all_models[i][num_prefill_inputs - 1].num_child_to_activate);
374	      }
375	    }
376	
377	    return prefill_inputs;
378	  }
379	
380	  // Copied from NewRequestPrefillActionObj::MatchPrefixCache
381	  /*!
382	   * \brief Match the request state entry with prefix cache, to skip prefilling common prefix
383	   * tokens. If the request state entry is not added to KVCache yet, this method will add/fork the
384	   * request in the KVCache, depending on the matching result from prefix cache.
385	   * \param estate The engine state.
386	   * \param[in, out] input The prefill input to be matched and updated.
387	   * \return The matched length in prefix cache.
388	   */
389	  int MatchPrefixCache(EngineState estate, PrefillInput* input) final {
390	    RequestStateEntry rsentry = input->rsentry;
391	    if (estate->prefix_cache->Mode() == PrefixCacheMode::kDisable) {
392	      return 0;
393	    }
394	    if (rsentry->parent_idx == -1 && rsentry->status == RequestStateStatus::kPending &&
395	        !estate->prefix_cache->HasSequence(rsentry->mstates[0]->internal_id)) {
396	      std::vector<int32_t> tokens = GetConcatPrefillInputData(rsentry->mstates[0]);
397	      if (tokens.empty()) {
398	        // If the RequestStateEntry is of empty input data, or not fully tokenized, do nothing
399	        // and return.
400	        return 0;
401	      }
402	      PrefixCacheMatchedResult result = estate->prefix_cache->InsertSequence(
403	          rsentry->mstates[0]->internal_id, tokens, models_[0]->GetSlidingWindowSize(),
404	          models_[0]->GetAttentionSinkSize());
405	
406	      if (result.prefilled_offset == 0) {
407	        // Add new sequence
408	        TVM_FFI_ICHECK_EQ(result.forked_seq_id, -1);
409	        TVM_FFI_ICHECK_EQ(result.reused_seq_id, -1);
410	        TVM_FFI_ICHECK_EQ(result.reused_seq_pop_last_tokens, 0);
411	        for (int model_id = 0; model_id < static_cast<int>(models_.size()); ++model_id) {
412	          Model model = models_[model_id];
413	          RequestModelState mstate = rsentry->mstates[model_id];
414	          model->AddNewSequence(rsentry->mstates[0]->internal_id);
415	          // Enable sliding window for the sequence if it is not a parent.
416	          if (rsentry->child_indices.empty()) {
417	            model->EnableSlidingWindowForSeq(rsentry->mstates[0]->internal_id);
418	          }
419	          DisaggConfig disagg_config = mstate->request->generation_cfg->debug_config.disagg_config;
420	          models_[model_id]->DisaggMarkKVSend(
421	              mstate->internal_id, disagg_config.kv_window_begin.value_or(0),
422	              disagg_config.kv_append_metadata[model_id], disagg_config.dst_group_offset.value());
423	        }
424	      } else {
425	        if (result.forked_seq_id != -1) {
426	          TVM_FFI_ICHECK_EQ(result.reused_seq_id, -1);
427	          TVM_FFI_ICHECK_EQ(result.reused_seq_pop_last_tokens, 0);
428	          // Fork from active sequence
429	          for (int model_id = 0; model_id < static_cast<int>(models_.size()); ++model_id) {
430	            Model model = models_[model_id];
431	            RequestModelState mstate = rsentry->mstates[model_id];
432	            model->ForkSequence(result.forked_seq_id, rsentry->mstates[0]->internal_id,
433	                                result.prefilled_offset);
434	            // Enable sliding window for the sequence if it is not a parent.
435	            if (rsentry->child_indices.empty()) {
436	              model->EnableSlidingWindowForSeq(rsentry->mstates[0]->internal_id);
437	            }
438	            DisaggConfig disagg_config =
439	                mstate->request->generation_cfg->debug_config.disagg_config;
440	            models_[model_id]->DisaggMarkKVSend(
441	                mstate->internal_id, disagg_config.kv_window_begin.value_or(0),
442	                disagg_config.kv_append_metadata[model_id], disagg_config.dst_group_offset.value());
443	          }
444	        } else {
445	          // Reuse recycling sequence
446	          TVM_FFI_ICHECK_EQ(result.forked_seq_id, -1);
447	          estate->id_manager.RecycleId(rsentry->mstates[0]->internal_id);
448	          for (int i = 0; i < rsentry->mstates.size(); ++i) {
449	            rsentry->mstates[i]->internal_id = result.reused_seq_id;
450	          }
451	          if (result.reused_seq_pop_last_tokens > 0) {
452	            for (Model model : models_) {
453	              model->PopNFromKVCache(rsentry->mstates[0]->internal_id,
454	                                     result.reused_seq_pop_last_tokens);
455	            }
456	          }
457	          for (int model_id = 0; model_id < static_cast<int>(models_.size()); ++model_id) {
458	            RequestModelState mstate = rsentry->mstates[model_id];
459	            DisaggConfig disagg_config =
460	                mstate->request->generation_cfg->debug_config.disagg_config;
461	            models_[model_id]->DisaggMarkKVSend(
462	                mstate->internal_id, disagg_config.kv_window_begin.value_or(0),
463	                disagg_config.kv_append_metadata[model_id], disagg_config.dst_group_offset.value());
464	          }
465	        }
466	      }
467	      // Pop matched prefix
468	      if (result.prefilled_offset) {
469	        for (int i = 0; i < rsentry->mstates.size(); ++i) {
470	          PopPrefillInputData(rsentry->mstates[i], result.prefilled_offset);
471	        }
472	      }
473	      // Update max prefill length
474	      input->max_prefill_length =
475	          std::min(input->max_prefill_length, rsentry->mstates[0]->GetInputLength());
476	      return result.prefilled_offset;
477	    }
478	    return 0;
479	  }
480	
481	  /*! \brief Workspace of each model. */
482	  std::vector<ModelWorkspace> model_workspaces_;
483	  /*! \brief The stream callback function to passes back the sampled results after prefill. */
484	  FRequestStreamCallback request_stream_callback_;
485	  /*! \brief The device which we run synchronization for after prefill. */
486	  Device device_;
487	  /*! \brief The compute stream to run synchronization for. */
488	  TVMStreamHandle compute_stream_ = nullptr;
489	};
490	
491	EngineAction EngineAction::DisaggRemoteSend(
492	    Array<Model> models, std::vector<ModelWorkspace> model_workspaces, EngineConfig engine_config,
493	    std::vector<tvm::ffi::json::Object> model_configs, Optional<EventTraceRecorder> trace_recorder,
494	    FRequestStreamCallback request_stream_callback, Device device) {
495	  return EngineAction(tvm::ffi::make_object<DisaggRemoteSendActionObj>(
496	      std::move(models), std::move(model_workspaces), std::move(engine_config),
497	      std::move(model_configs), std::move(trace_recorder), std::move(request_stream_callback),
498	      device));
499	}
500	
501	}  // namespace serve
502	}  // namespace llm
503	}  // namespace mlc
