14	namespace mlc {
15	namespace llm {
16	namespace serve {
17	
18	using tvm::support::NVTXScopedRange;
19	
20	/*!
21	 * \brief The action that runs prefill preparation in disaggregation system.
22	 * It picks a new request, reserve its KV data locations, and returns the
23	 * KV data locations and the matched prefix length in prefix cache.
24	 */
25	class DisaggPrepareReceiveActionObj : public BatchPrefillBaseActionObj {
26	 public:
27	  explicit DisaggPrepareReceiveActionObj(Array<Model> models, EngineConfig engine_config,
28	                                         std::vector<tvm::ffi::json::Object> model_configs,
29	                                         Optional<EventTraceRecorder> trace_recorder,
30	                                         FRequestStreamCallback request_stream_callback)
31	      : BatchPrefillBaseActionObj(std::move(models), std::move(engine_config),
32	                                  std::move(model_configs), std::move(trace_recorder)),
33	        request_stream_callback_(std::move(request_stream_callback)) {
34	    TVM_FFI_ICHECK(kv_state_kind_ == KVStateKind::kKVCache)
35	        << "Only PagedKVCache supports prefill preparation and KV migration";
36	  }
37	
38	  Array<Request> Step(EngineState estate) final {
39	    std::vector<Request> processed_requests;
40	
41	    // - Find the requests in `waiting_queue` that can prefill in this step.
42	    std::optional<PrefillInput> prefill_input_opt;
43	    while (true) {
44	      prefill_input_opt = GetRequestStateEntriesToPrefill(estate);
45	      if (!prefill_input_opt.has_value()) {
46	        break;
47	      }
48	      PrefillInput prefill_input = prefill_input_opt.value();
49	      int prefix_matched_length = 0;
50	      Request request = prefill_input.rsentry->request;
51	      processed_requests.push_back(request);
52	      int total_input_length = 0;
53	      for (const Data& data : request->inputs) {
54	        total_input_length += data->GetLength();
55	      }
56	
57	      {
58	        NVTXScopedRange nvtx_scope("DisaggPrepareReceive matching prefix");
59	        prefix_matched_length = MatchPrefixCache(estate, &prefill_input);
60	      }
61	
62	      auto tstart = std::chrono::high_resolution_clock::now();
63	
64	      // - Update status of request states from pending to alive.
65	      Array<String> request_ids;
66	      std::vector<RequestState> rstates_of_entries;
67	      std::vector<RequestStateStatus> status_before_prefill;
68	      UpdateRequestToAlive({prefill_input}, estate, &request_ids, &rstates_of_entries,
69	                           &status_before_prefill);
70	      // "UpdateRequestToAlive" may add the request to the engine's running request queue.
71	      // We erase it since it's pending for the prefill instance to send the KV data over.
72	      if (!estate->running_queue.empty() && estate->running_queue.back().same_as(request)) {
73	        estate->running_queue.pop_back();
74	      }
75	
76	      // - Add the sequence to each model.
77	      int prefill_length = -1;
78	      Tensor logits_for_sample{nullptr};
79	      std::vector<Shape> kv_append_metadata;
80	      kv_append_metadata.reserve(models_.size());
81	      for (int model_id = 0; model_id < static_cast<int>(models_.size()); ++model_id) {
82	        const RequestStateEntry& rsentry = prefill_input.rsentry;
83	        RequestModelState mstate = rsentry->mstates[model_id];
84	        Array<Data> input_data = mstate->inputs;
85	        mstate->inputs.clear();
86	        int input_length = prefill_input.max_prefill_length;
87	        if (prefill_length == -1) {
88	          prefill_length = input_length;
89	        } else {
90	          TVM_FFI_ICHECK_EQ(prefill_length, input_length);
91	        }
92	        mstate->num_prefilled_tokens += input_length;
93	
94	        TVM_FFI_ICHECK(mstate->draft_output_tokens.empty());
95	        TVM_FFI_ICHECK(mstate->draft_token_slots.empty());
96	        if (status_before_prefill[0] == RequestStateStatus::kPending &&
97	            !estate->prefix_cache->HasSequence(mstate->internal_id)) {
98	          // Add the sequence to the model, or fork the sequence from its parent.
99	          // If the sequence is already in prefix cache, it has also been added/forked in the
100	          // KVCache.
101	          if (rsentry->parent_idx == -1) {
102	            models_[model_id]->AddNewSequence(mstate->internal_id);
103	          } else {
104	            models_[model_id]->ForkSequence(
105	                rstates_of_entries[0]->entries[rsentry->parent_idx]->mstates[model_id]->internal_id,
106	                mstate->internal_id);
107	          }
108	          // Enable sliding window for the sequence if it is not a parent.
109	          if (rsentry->child_indices.empty()) {
110	            models_[model_id]->EnableSlidingWindowForSeq(mstate->internal_id);
111	          }
112	        }
113	
114	        // Record the of the prefilled inputs for prefix cache update.
115	        for (int j = 0; j < static_cast<int>(input_data.size()); ++j) {
116	          if (!model_id && !prefill_input.is_decode) {
117	            mstate->prefilled_inputs.push_back(input_data[j]);
118	          }
119	        }
120	
121	        int64_t request_internal_id = mstate->internal_id;
122	        RECORD_EVENT(trace_recorder_, request_ids, "start prefill");
123	        Shape compressed_kv_append_metadata = {0};
124	        if (prefill_length > 0) {
125	          compressed_kv_append_metadata =
126	              models_[model_id]->DisaggPrepareKVRecv(request_internal_id, prefill_length);
127	        }
128	        kv_append_metadata.push_back(compressed_kv_append_metadata);
129	        RECORD_EVENT(trace_recorder_, request_ids, "finish prefill");
130	      }
131	
132	      // - Commit the prefix cache changes from previous round of action.
133	      // Note: we commit prefix cache changes here to overlap this commit with the GPU execution.
134	      estate->prefix_cache->CommitSequenceExtention();
135	
136	      auto tend = std::chrono::high_resolution_clock::now();
137	
138	      // - Remove the request from the waiting queue.
139	      auto it_request =
140	          std::find(estate->waiting_queue.begin(), estate->waiting_queue.end(), request);
141	      TVM_FFI_ICHECK(it_request != estate->waiting_queue.end());
142	      estate->waiting_queue.erase(it_request);
143	
144	      {
145	        NVTXScopedRange nvtx_scope("Call request stream callback");
146	        tvm::ffi::json::Object response_body;
147	        response_body.Set("prompt_length", static_cast<int64_t>(total_input_length));
148	        response_body.Set("prefix_matched_length", static_cast<int64_t>(prefix_matched_length));
149	        // We further flatten the metadata array of all models into a single array.
150	        tvm::ffi::json::Array kv_append_metadata_arr;
151	        for (const Shape& compressed_kv_append_metadata : kv_append_metadata) {
152	          for (int64_t value : compressed_kv_append_metadata) {
153	            kv_append_metadata_arr.push_back(value);
154	          }
155	          TVM_FFI_ICHECK(!compressed_kv_append_metadata.empty());
156	          int num_segments = compressed_kv_append_metadata[0];
157	          TVM_FFI_ICHECK_EQ(compressed_kv_append_metadata.size(), num_segments * 2 + 1);
158	          int transmission_length = 0;
159	          for (int i = 0; i < num_segments; ++i) {
160	            transmission_length += compressed_kv_append_metadata[i * 2 + 2];
161	          }
162	          TVM_FFI_ICHECK_EQ(transmission_length, prefill_length);
163	        }
164	
165	        response_body.Set(
166	            "kv_append_metadata",
167	            Base64Encode(std::string(tvm::ffi::json::Stringify(kv_append_metadata_arr))));
168	
169	        tvm::ffi::json::Object usage;
170	        usage.Set("prompt_tokens", static_cast<int64_t>(0));
171	        usage.Set("completion_tokens", static_cast<int64_t>(0));
172	        usage.Set("total_tokens", static_cast<int64_t>(0));
173	        usage.Set("extra", response_body);
174	        RequestStreamOutput stream_output =
175	            RequestStreamOutput::Usage(request->id, std::string(tvm::ffi::json::Stringify(usage)));
176	        // - Invoke the stream callback function once for all collected requests.
177	        request_stream_callback_(Array<RequestStreamOutput>{stream_output});
178	      }
179	    }
180	
181	    for (const Request& request : processed_requests) {
182	      TVM_FFI_ICHECK(std::find(estate->running_queue.begin(), estate->running_queue.end(),
183	                               request) == estate->running_queue.end());
184	    }
185	    return {processed_requests};
186	  }
187	
188	 private:
189	  // Mimicked from BatchPrefillBaseActionObj::GetRequestStateEntriesToPrefill
190	  std::optional<PrefillInput> GetRequestStateEntriesToPrefill(EngineState estate) {
191	    const std::vector<RequestStateEntry>* running_rsentries;
192	    {
193	      NVTXScopedRange nvtx_scope("BatchDecode getting requests");
194	      running_rsentries = &estate->GetRunningRequestStateEntries();
195	      if (!(running_rsentries->size() <= models_[0]->GetNumAvailablePages())) {
196	        // Even the decode cannot be performed.
197	        // As a result, directly return without doing prefill.
198	        return {};
199	      }
200	    }
201	    int num_running_rsentries = static_cast<int>(running_rsentries->size());
202	
203	    Request request{nullptr};
204	    for (const Request& request_candidate : estate->waiting_queue) {
205	      if (request_candidate->generation_cfg->debug_config.disagg_config.kind ==
206	          DisaggRequestKind::kPrepareReceive) {
207	        request = request_candidate;
208	        break;
209	      }
210	    }
211	    if (!request.defined()) {
212	      // No request to prepare for prefill.
213	      return {};
214	    }
215	    TVM_FFI_ICHECK_EQ(
216	        request->generation_cfg->debug_config.disagg_config.kv_window_begin.value_or(0), 0);
217	
218	    std::vector<PrefillInput> prefill_input_for_all_models;
219	    prefill_input_for_all_models.reserve(models_.size());
220	
221	    // We first collect the inputs that can be prefilled for each model.
222	    // The inputs for each model are expected to be exactly the same.
223	    for (int i = 0; i < static_cast<int>(models_.size()); ++i) {
224	      NVTXScopedRange nvtx_scope("Process request " + request->id);
225	
226	      PrefillInput prefill_input;
227	      // - Try to prefill pending requests.
228	      int num_available_pages = models_[i]->GetNumAvailablePages();
229	      int current_total_seq_len = models_[i]->GetCurrentTotalSequenceLength();
230	
231	      RequestState rstate = estate->GetRequestState(request);
232	      bool prefill_stops = false;
233	      for (int j = 1; j < static_cast<int>(rstate->entries.size()); ++j) {
234	        TVM_FFI_ICHECK(rstate->entries[j]->mstates[i]->inputs.empty())
235	            << "Re-prefill of preempted requests is not supported by prefill preparation.";
236	      }
237	      const RequestStateEntry& rsentry = rstate->entries[0];
238	      TVM_FFI_ICHECK(!rsentry->mstates[i]->inputs.empty())
239	          << "The request entry must have pending inputs.";
240	
241	      // Todo: handle the case that input length is 1.
242	
243	      int input_length = rsentry->mstates[i]->GetInputLength();
244	      // Update the input length with the requested KV window, where "[begin:end]"
245	      // means the KV range to prefill on a prefill instance.
246	      int kv_window_begin =
247	          request->generation_cfg->debug_config.disagg_config.kv_window_begin.value_or(0);
248	      int kv_window_end =
249	          request->generation_cfg->debug_config.disagg_config.kv_window_end.value_or(input_length);
250	      TVM_FFI_ICHECK_EQ(kv_window_begin, 0);
251	      if (kv_window_end < 0) {
252	        kv_window_end = input_length + kv_window_end;
253	      }
254	      TVM_FFI_ICHECK_GE(kv_window_end, 0);
255	      TVM_FFI_ICHECK_LT(kv_window_end, input_length)
256	          << "Prefill the full input on the remote machine is not supported.";
257	      int orig_input_length = input_length;
258	      input_length = kv_window_end;
259	
260	      int num_require_pages = (input_length + engine_config_->kv_cache_page_size - 1) /
261	                              engine_config_->kv_cache_page_size;
262	      bool sliding_window_enabled = sliding_window_sizes_[i] != -1;
263	      int num_required_pages_under_sliding_window = std::numeric_limits<int>::max();
264	      if (sliding_window_enabled) {
265	        // Sliding window for model i is enabled.
266	        int max_single_request_page_requirement =
267	            1 + (sliding_window_sizes_[i] + engine_config_->kv_cache_page_size - 1) /
268	                    engine_config_->kv_cache_page_size;
269	        int num_total_prefilled_tokens = rsentry->mstates[i]->num_prefilled_tokens;
270	        int num_pages_in_use = (std::min(num_total_prefilled_tokens, sliding_window_sizes_[i]) +
271	                                engine_config_->kv_cache_page_size - 1) /
272	                               engine_config_->kv_cache_page_size;
273	        num_required_pages_under_sliding_window =
274	            max_single_request_page_requirement - num_pages_in_use;
275	        num_require_pages = std::min(num_require_pages, num_required_pages_under_sliding_window);
276	        TVM_FFI_ICHECK_GE(num_require_pages, 0);
277	      }
278	
279	      // Check if the entire request state entry can fit for prefill.
280	      bool can_prefill = false;
281	      {
282	        NVTXScopedRange nvtx_scope("Attempt");
283	        for (int num_child_to_activate = rsentry->child_indices.size(); num_child_to_activate >= 0;
284	             --num_child_to_activate) {
285	          while (!HasPrefillSpace(num_require_pages, sliding_window_enabled, num_running_rsentries,
286	                                  num_available_pages, current_total_seq_len, input_length,
287	                                  engine_config_->max_total_sequence_length)) {
288	            if (!estate->prefix_cache->TryFreeMemory()) break;
289	            // Update number of available pages after memory free.
290	            num_available_pages = models_[i]->GetNumAvailablePages();
291	            current_total_seq_len = models_[i]->GetCurrentTotalSequenceLength();
292	          }
293	          if (CanPrefill(estate, 1 + num_child_to_activate, input_length, num_require_pages,
294	                         num_available_pages, current_total_seq_len, num_running_rsentries,
295	                         kv_state_kind_, sliding_window_enabled)) {
296	            prefill_input = {rsentry, input_length, num_child_to_activate, /*is_decode=*/false};
297	            can_prefill = true;
298	            break;
299	          }
300	        }
301	      }
302	      if (!can_prefill) {
303	        return std::nullopt;
304	      }
305	      rsentry->mstates[i]->inputs =
306	          SplitData(rsentry->mstates[i]->inputs, orig_input_length, kv_window_end).first;
307	      prefill_input_for_all_models.push_back(prefill_input);
308	    }
309	
310	    // Prefill inputs of all models should be the same.
311	    TVM_FFI_ICHECK(!prefill_input_for_all_models.empty());
312	    PrefillInput prefill_input = prefill_input_for_all_models[0];
313	    {
314	      NVTXScopedRange nvtx_scope("reduction");
315	      for (int i = 1; i < static_cast<int>(prefill_input_for_all_models.size()); ++i) {
316	        TVM_FFI_ICHECK(prefill_input_for_all_models[i].rsentry.same_as(prefill_input.rsentry));
317	        TVM_FFI_ICHECK_EQ(prefill_input_for_all_models[i].max_prefill_length,
318	                          prefill_input.max_prefill_length);
319	        TVM_FFI_ICHECK_EQ(prefill_input_for_all_models[i].num_child_to_activate,
320	                          prefill_input.num_child_to_activate);
321	      }
322	    }
323	
324	    return prefill_input;
325	  }
326	
327	  // Mimicked from BatchPrefillBaseActionObj::CanPrefill
328	  bool CanPrefill(EngineState estate, int num_prefill_rsentries, int total_input_length,
329	                  int num_required_pages, int num_available_pages, int current_total_seq_len,
330	                  int num_running_rsentries, KVStateKind kv_state_kind,
331	                  bool sliding_window_enabled) {
332	    // No exceeding of the maximum allowed requests that can
333	    // run simultaneously.
334	    int spec_factor = engine_config_->speculative_mode != SpeculativeMode::kDisable
335	                          ? (estate->spec_draft_length + 1)
336	                          : 1;
337	    if ((num_running_rsentries + num_prefill_rsentries) * spec_factor >
338	        std::min(static_cast<int64_t>(engine_config_->max_num_sequence),
339	                 engine_config_->prefill_chunk_size)) {
340	      return false;
341	    }
342	
343	    // NOTE: The conditions are heuristic and can be revised.
344	    // Cond 1: at least one decode can be performed after prefill.
345	    // Cond 2: number of total tokens after "x" times of decode does not
346	    // exceed the limit, where "x" is a watermark number can
347	    // be configured and adjusted in the future.
348	    if (num_required_pages + 400 > num_available_pages) {
349	      return false;
350	    }
351	    return HasPrefillSpace(num_required_pages, sliding_window_enabled,
352	                           (num_running_rsentries + num_prefill_rsentries), num_available_pages,
353	                           current_total_seq_len, total_input_length,
354	                           engine_config_->max_total_sequence_length);
355	  }
356	
357	  // Mimicked from NewRequestPrefillActionObj::MatchPrefixCache
358	  int MatchPrefixCache(EngineState estate, PrefillInput* input) final {
359	    RequestStateEntry rsentry = input->rsentry;
360	    if (estate->prefix_cache->Mode() == PrefixCacheMode::kDisable) {
361	      return 0;
362	    }
363	    if (rsentry->parent_idx == -1 && rsentry->status == RequestStateStatus::kPending &&
364	        !estate->prefix_cache->HasSequence(rsentry->mstates[0]->internal_id)) {
365	      std::vector<int32_t> tokens = GetConcatPrefillInputData(rsentry->mstates[0]);
366	      if (tokens.empty()) {
367	        // If the RequestStateEntry is of empty input data, or not fully tokenized, do nothing
368	        // and return.
369	        return 0;
370	      }
371	      PrefixCacheMatchedResult result = estate->prefix_cache->InsertSequence(
372	          rsentry->mstates[0]->internal_id, tokens, models_[0]->GetSlidingWindowSize(),
373	          models_[0]->GetAttentionSinkSize());
374	
375	      if (result.prefilled_offset == 0) {
376	        // Add new sequence
377	        TVM_FFI_ICHECK_EQ(result.forked_seq_id, -1);
378	        TVM_FFI_ICHECK_EQ(result.reused_seq_id, -1);
379	        TVM_FFI_ICHECK_EQ(result.reused_seq_pop_last_tokens, 0);
380	        for (Model model : models_) {
381	          model->AddNewSequence(rsentry->mstates[0]->internal_id);
382	          // Enable sliding window for the sequence if it is not a parent.
383	          if (rsentry->child_indices.empty()) {
384	            model->EnableSlidingWindowForSeq(rsentry->mstates[0]->internal_id);
385	          }
386	        }
387	      } else {
388	        if (result.forked_seq_id != -1) {
389	          TVM_FFI_ICHECK_EQ(result.reused_seq_id, -1);
390	          TVM_FFI_ICHECK_EQ(result.reused_seq_pop_last_tokens, 0);
391	          // Fork from active sequence
392	          for (Model model : models_) {
393	            model->ForkSequence(result.forked_seq_id, rsentry->mstates[0]->internal_id,
394	                                result.prefilled_offset);
395	            // Enable sliding window for the sequence if it is not a parent.
396	            if (rsentry->child_indices.empty()) {
397	              model->EnableSlidingWindowForSeq(rsentry->mstates[0]->internal_id);
398	            }
399	          }
400	        } else {
401	          // Reuse recycling sequence
402	          TVM_FFI_ICHECK_EQ(result.forked_seq_id, -1);
403	          estate->id_manager.RecycleId(rsentry->mstates[0]->internal_id);
404	          for (int i = 0; i < rsentry->mstates.size(); ++i) {
405	            rsentry->mstates[i]->internal_id = result.reused_seq_id;
406	          }
407	          if (result.reused_seq_pop_last_tokens > 0) {
408	            for (Model model : models_) {
409	              model->PopNFromKVCache(rsentry->mstates[0]->internal_id,
410	                                     result.reused_seq_pop_last_tokens);
411	            }
412	          }
413	        }
414	      }
415	      // Pop matched prefix
416	      if (result.prefilled_offset) {
417	        for (int i = 0; i < rsentry->mstates.size(); ++i) {
418	          PopPrefillInputData(rsentry->mstates[i], result.prefilled_offset);
419	        }
420	      }
421	      // Update max prefill length
422	      input->max_prefill_length =
423	          std::min(input->max_prefill_length, rsentry->mstates[0]->GetInputLength());
424	      return result.prefilled_offset;
425	    }
426	    return 0;
427	  }
428	
429	  /*!
430	   * \brief The stream callback function to passes back the KV cache metadata
431	   * and prefix matched length in prefix cache.
432	   */
433	  FRequestStreamCallback request_stream_callback_;
434	};
435	
436	EngineAction EngineAction::DisaggPrepareReceive(Array<Model> models, EngineConfig engine_config,
437	                                                std::vector<tvm::ffi::json::Object> model_configs,
438	                                                Optional<EventTraceRecorder> trace_recorder,
439	                                                FRequestStreamCallback request_stream_callback) {
440	  return EngineAction(tvm::ffi::make_object<DisaggPrepareReceiveActionObj>(
441	      std::move(models), std::move(engine_config), std::move(model_configs),
442	      std::move(trace_recorder), std::move(request_stream_callback)));
443	}
444	
445	}  // namespace serve
446	}  // namespace llm
447	}  // namespace mlc
